import React, { useState } from 'react';
import { useIdioma } from '../context/IdiomaContext';

const ContactForm = () => {
  const { t } = useIdioma();
  const [formData, setFormData] = useState({ nombre: '', correo: '', direccion: '', servicio: '', mensaje: '' });

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData((prev) => ({ ...prev, [name]: value }));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    alert(`✉️ ${t('contacto', 'formTitle')} - ${formData.nombre}`);
  };

  return (
    <section id="contacto" className="contacto" style={{ scrollMarginTop: '80px' }}>
      <div className="container">
        <div className="section-header">
          <i className="fas fa-paper-plane"></i>
          <h2>{t('contacto', 'title')}</h2>
          <p>{t('contacto', 'desc')}</p>
        </div>
        <div className="contacto-content">
          <div className="formulario">
            <h3><i className="fas fa-edit"></i> {t('contacto', 'formTitle')}</h3>
            <form onSubmit={handleSubmit}>
              <div className="form-group">
                <label htmlFor="nombre"><i className="fas fa-user"></i> {t('contacto', 'nombre')}:</label>
                <input type="text" id="nombre" name="nombre" value={formData.nombre} onChange={handleChange} required />
              </div>
              <div className="form-group">
                <label htmlFor="correo"><i className="fas fa-envelope"></i> {t('contacto', 'correo')}:</label>
                <input type="email" id="correo" name="correo" value={formData.correo} onChange={handleChange} required />
              </div>
              <div className="form-group">
                <label htmlFor="direccion"><i className="fas fa-map-marker-alt"></i> {t('contacto', 'direccion')}:</label>
                <input type="text" id="direccion" name="direccion" value={formData.direccion} onChange={handleChange} />
              </div>
              <div className="form-group">
                <label htmlFor="servicio"><i className="fas fa-list"></i> {t('contacto', 'servicioInteres')}:</label>
                <select id="servicio" name="servicio" value={formData.servicio} onChange={handleChange}>
                  <option value="">{t('contacto', 'selecciona')}</option>
                  <option value="red">Red Team</option>
                  <option value="blue">Blue Team</option>
                  <option value="purple">Purple Team</option>
                  <option value="consultoria">{t('servicios', 'consultoria')}</option>
                </select>
              </div>
              <div className="form-group">
                <label htmlFor="mensaje"><i className="fas fa-comment"></i> {t('contacto', 'mensaje')}:</label>
                <textarea id="mensaje" name="mensaje" rows={5} value={formData.mensaje} onChange={handleChange} required></textarea>
              </div>
              <button type="submit" className="btn-submit">
                <i className="fas fa-paper-plane"></i> {t('contacto', 'enviar')}
              </button>
            </form>
          </div>
          <div className="resultado">
            <h3><i className="fas fa-address-card"></i> {t('contacto', 'infoTitle')}</h3>
            <div className="datos-mostrados">
              {[
                { icon: 'fa-phone-alt', label: t('contacto', 'telefono'), value: '+591 12345678' },
                { icon: 'fa-envelope', label: t('contacto', 'correo'), value: 'info@blackcatciberseguridad.com' },
                { icon: 'fa-map-marker-alt', label: t('contacto', 'direccion'), value: 'Universidad Autónoma Tomás Frías' },
                { icon: 'fa-clock', label: t('contacto', 'horario'), value: 'Lunes a Viernes: 9:00 - 18:00' }
              ].map((dato, i) => (
                <div className="dato-item" key={i}>
                  <i className={`fas ${dato.icon}`}></i>
                  <div>
                    <strong>{dato.label}:</strong>
                    <span>{dato.value}</span>
                  </div>
                </div>
              ))}
            </div>
            <div className="mapa">
              <iframe src="https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d3800.0!2d-65.75!3d-19.58!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x0%3A0x0!2zMTnCsDM0JzQ4LjAiUyA2NcKwNDUnMDAuMCJX!5e0!3m2!1ses!2sbo!4v1600000000000" width="100%" height="200" style={{ border: 0 }} allowFullScreen loading="lazy" title="mapa"></iframe>
            </div>
          </div>
        </div>
      </div>
    </section>
  );
};

export default ContactForm;
